import React from 'react';
import ReactDOM from 'react-dom';
import './index.scss';
import App from './App';
import * as serviceWorker from './serviceWorker';
import 'bootstrap/dist/css/bootstrap.min.css';

/* GLOBAL VARIABLES */

// Changed secondary language to 'in' (India) or your preferred code
window.$primaryLanguage = 'en'; 
window.$secondaryLanguage = 'in'; 

// These IDs can be used for targeting specific styles in SCSS if needed
window.$primaryLanguageIconId = 'uk-flag-icon';
window.$secondaryLanguageIconId = 'india-flag-icon';


const savedTheme = localStorage.getItem('theme') || 'light';
document.body.setAttribute('data-theme', savedTheme);

ReactDOM.render(<App />, document.getElementById('root'));


serviceWorker.register();
